110	fun gibs(at: Vector2, gibAngle: Float = 1000f) {
111	    for (i in Assets.enemyGibs) {
112	        val angle = if (gibAngle == 1000f) (1f..359f).random() else gibAngle
113	        val force = vec2((15f..60f).random(), 0f).setAngleDeg(angle + (-25..25).random())
114	        val body = world().body {
115	            type = BodyDef.BodyType.DynamicBody
116	            position.set(at.x - 2f, at.y - 2f)
117	            linearDamping = 5f
118	            box(.3f, .1f) {
119	                friction = 10f //Tune
120	                filter {
121	                    categoryBits = Box2dCategories.gibs
122	                    maskBits = Box2dCategories.whatGibsHit
123	                }
124	            }
125	        }
126	
127	        val localPoint = vec2(-1f, 0f)
128	
129	        val gibEntity = engine().entity {
130	            with<TextureRegionComponent> {
131	                rotateWithTransform = true
132	                textureRegion = i
133	            }
134	            with<RenderableComponent> {
135	            }
136	            with<TransformComponent> {
137	                position.set(at)
138	            }
139	            with<Box2d> {
140	                this.body = body
141	            }
142	            with<GibComponent> {
143	                coolDownRange = 1f..3f
