297	fun bodyForRegion(
298	    at: Vector2,
299	    colliderCategoryBits: Short,
300	    colliderMaskBits: Short,
301	    detectorBits: Short,
302	    detectorMaskBits: Short,
303	    sensorBits: Short,
304	    sensorMaskBits: Short,
305	    pixelWidth: Int = 24,
306	    pixelHeight: Int = 48
307	): Body {
308	    val widthInMeters = pixelWidth / PIXELS_PER_METER
309	    val heightInMeters = pixelHeight / PIXELS_PER_METER
310	
311	    val bottomBoxWidth = widthInMeters
312	    val bottomBoxHeight = widthInMeters / 2
313	    val halfHeight = heightInMeters / 2
314	
315	    val box2dBody = world().body {
316	        type = BodyDef.BodyType.DynamicBody
317	        position.set(at)
318	        fixedRotation = true
319	        //Bottom projection box
320	        box(bottomBoxWidth, bottomBoxHeight, vec2(0f, halfHeight - bottomBoxHeight / 2)) {
321	            density = PLAYER_DENSITY
322	            filter {
323	                categoryBits = colliderCategoryBits
324	                maskBits = colliderMaskBits
325	            }
326	        }
327	        box(widthInMeters, heightInMeters, vec2(0f, 0f)) {
328	            isSensor = true
329	            filter {
330	                categoryBits = detectorBits
331	                maskBits = detectorMaskBits
332	            }
333	        }
334	        circle(2.5f * heightInMeters, vec2(0f, 0f)) {
335	            isSensor = true
336	            filter {
337	                categoryBits = sensorBits
338	                maskBits = sensorMaskBits
339	            }
340	        }
341	        linearDamping = SHIP_LINEAR_DAMPING
342	        angularDamping = SHIP_ANGULAR_DAMPING
343	    }
344	    return box2dBody
345	}
