433	fun playerWeapon(playerEntity: Entity, anchor: String = "green"): Entity {
434	    return engine().entity {
435	        with<TransformComponent>()
436	        with<TextureRegionComponent> {
437	            rotateWithTransform = true
438	            isVisible = true
439	            originX = 0f
440	            originY = 0f
441	        }
442	        with<RenderableComponent> {
443	            layer = 1
444	            renderableType = RenderableType.Sprite
445	        }
446	        val weapon = WeaponDefinition.spas12.getWeapon()
447	        with<WeaponComponent> {
448	            currentWeapon = weapon
449	        }
450	        with<CalculatedPositionComponent> {
451	            calculate = {
452	                calcPos.set(playerEntity.anchors().transformedPoints[anchor]!!)
453	            }
454	        }
455	        with<CalculatedRotationComponent> {
456	            calculate = {
457	                playerEntity.anchors().transformedPoints[anchor]!!.cpy().sub(playerEntity.transform().position)
458	                    .angleRad()
459	            }
460	        }
461	        with<FunctionsComponent> {
462	            functions["SetVisibility"] = { w ->
463	                w.textureRegionComponent().isVisible = playerEntity.playerControl().aiming
464	            }
465	            functions["UpdateWeaponSprite"] = { w ->
466	                val direction = playerEntity.animation().currentDirection
467	                w.textureRegionComponent().textureRegion = Assets.weapons.getSpriteFor(w.weapon().currentWeapon, direction)
468	                when (direction) {
469	                    CardinalDirection.East -> w.textureRegionComponent().textureRegion.flip(false, false)
470	                    CardinalDirection.North -> w.textureRegionComponent().textureRegion.flip(false, false)
471	                    CardinalDirection.South -> w.textureRegionComponent().textureRegion.flip(false, false)
472	                    CardinalDirection.West -> w.textureRegionComponent().textureRegion.flip(false, true)
473	                }
474	            }
475	        }
476	    }
477	}
