479	fun semicircle(): List<Vector2> {
480	    val radius = 5f
481	    val vs = mutableListOf<Vector2>()
482	    vs.add(vec2(0f, 0f))
483	    for (i in 0 until 7) {
484	        val angle = (i / 6.0f * 180 * degreesToRadians)
485	        vs.add(vec2(radius * MathUtils.cos(angle), radius * MathUtils.sin(angle)))
486	    }
487	    return vs
488	}
